import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        R = int(next(it)); C = int(next(it))
        parts = []
        for y in range(1, C+1):
            horiz = 'R' if y % 2 == 1 else 'L'
            parts.append(horiz * R)
            if y != C:
                parts.append('U')
        out.append(''.join(parts))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

